const body = $json.body || {};
const downSince = body.downSince ? new Date(body.downSince) : null;
const now = new Date();

let downDuration = '未知';
if (downSince && !isNaN(downSince.getTime())) {
  const diffMs = now - downSince;
  const diffMin = Math.floor(diffMs / 60000);
  downDuration = diffMin >= 60
    ? `${Math.floor(diffMin / 60)} 小時 ${diffMin % 60} 分鐘`
    : diffMin > 0 ? `${diffMin} 分鐘` : '不到 1 分鐘';
}

const nowStr = now.toLocaleString('zh-TW', { timeZone: 'Asia/Taipei', hour12: false });
const lines = [
  '🌐 **網路連線已恢復** ✅',
  `📅 ${nowStr}`,
  `⏱️ 斷線時長：${downDuration}`,
];
if (body.unstable) {
  lines.push(`⚠️ 過去 5 分鐘已斷線 ${body.dropCount} 次，網路不穩定！`);
}
return [{ json: { content: lines.join('\n') } }];

